from __future__ import annotations

"""Production ASR / forced-alignment service for subtitle word timing.

Priority order:
1. Speech marks JSON generated by a TTS provider, when supplied.
2. WhisperX alignment, when installed and enabled.
3. OpenAI Whisper segment timestamps, when installed and enabled.
4. Even distribution fallback only when explicitly allowed by production gate.

This replaces the old hardcoded 6-second stub. Production must use a real
alignment path or set ALLOW_ASR_STUB=true as an emergency bypass.
"""

import json
import os
import shutil
import subprocess
from pathlib import Path
from typing import Any, Iterable, List

from app.core.config import settings
from app.core.production_gate import ensure_stub_allowed, env_bool, is_production_or_staging


class ASRAlignmentError(RuntimeError):
    pass


class ASRAlignmentService:
    def align(
        self,
        audio_path: str,
        transcript: str,
        *,
        speech_marks_path: str | None = None,
        language: str | None = None,
    ) -> List[dict]:
        words = transcript.split()
        if not words:
            return []

        if speech_marks_path:
            marks = self._align_from_speech_marks(speech_marks_path, words)
            if marks:
                return marks

        if env_bool("ENABLE_WHISPERX_ALIGNMENT", True):
            try:
                marks = self._align_with_whisperx(audio_path, transcript, language=language)
                if marks:
                    return marks
            except Exception:
                if is_production_or_staging() and not env_bool("ALLOW_ASR_STUB", False):
                    raise

        if env_bool("ENABLE_WHISPER_ALIGNMENT", True):
            try:
                marks = self._align_with_whisper(audio_path, transcript, language=language)
                if marks:
                    return marks
            except Exception:
                if is_production_or_staging() and not env_bool("ALLOW_ASR_STUB", False):
                    raise

        ensure_stub_allowed("ASR alignment even-distribution fallback", allow_env="ALLOW_ASR_STUB")
        duration_sec = self._probe_audio_duration(audio_path)
        if duration_sec <= 0:
            raise ASRAlignmentError(f"Invalid audio duration: {audio_path}")
        return self._evenly_distribute(words, duration_sec)

    def _align_from_speech_marks(self, speech_marks_path: str, transcript_words: list[str]) -> list[dict]:
        path = Path(speech_marks_path)
        if not path.exists():
            return []
        raw = path.read_text(encoding="utf-8").strip()
        if not raw:
            return []

        marks: list[dict[str, Any]] = []
        if raw.startswith("["):
            data = json.loads(raw)
            source_iter: Iterable[dict[str, Any]] = data
        else:
            source_iter = (json.loads(line) for line in raw.splitlines() if line.strip())

        for item in source_iter:
            value = item.get("value") or item.get("word") or item.get("text")
            if not value:
                continue
            start = item.get("start_sec")
            if start is None and item.get("time") is not None:
                start = float(item["time"]) / 1000.0
            if start is None and item.get("start") is not None:
                start = float(item["start"])
            end = item.get("end_sec")
            if end is None and item.get("end") is not None:
                end = float(item["end"])
            if end is None:
                end = float(start) + 0.18
            marks.append({"word": str(value), "start_sec": round(float(start), 3), "end_sec": round(float(end), 3)})

        return self._normalize_word_count(marks, transcript_words)

    def _align_with_whisperx(self, audio_path: str, transcript: str, *, language: str | None) -> list[dict]:
        import whisperx  # type: ignore[import]
        import torch  # type: ignore[import]

        device = os.getenv("WHISPERX_DEVICE", "cuda" if torch.cuda.is_available() else "cpu")
        compute_type = os.getenv("WHISPERX_COMPUTE_TYPE", "float16" if device == "cuda" else "int8")
        model_name = os.getenv("WHISPERX_MODEL", "small")
        model = whisperx.load_model(model_name, device=device, compute_type=compute_type, language=language)
        result = model.transcribe(audio_path, batch_size=int(os.getenv("WHISPERX_BATCH_SIZE", "8")), language=language)
        lang = language or result.get("language") or "en"
        align_model, metadata = whisperx.load_align_model(language_code=lang, device=device)
        aligned = whisperx.align(result["segments"], align_model, metadata, audio_path, device, return_char_alignments=False)
        words: list[dict] = []
        for item in aligned.get("word_segments", []):
            word = item.get("word")
            if word and item.get("start") is not None and item.get("end") is not None:
                words.append({"word": word, "start_sec": round(float(item["start"]), 3), "end_sec": round(float(item["end"]), 3)})
        return self._normalize_word_count(words, transcript.split())

    def _align_with_whisper(self, audio_path: str, transcript: str, *, language: str | None) -> list[dict]:
        import whisper  # type: ignore[import]

        model_name = os.getenv("WHISPER_MODEL", "base")
        model = whisper.load_model(model_name)
        result = model.transcribe(audio_path, language=language, word_timestamps=True)
        words: list[dict] = []
        for seg in result.get("segments", []):
            for item in seg.get("words", []) or []:
                word = str(item.get("word", "")).strip()
                if word and item.get("start") is not None and item.get("end") is not None:
                    words.append({"word": word, "start_sec": round(float(item["start"]), 3), "end_sec": round(float(item["end"]), 3)})
        if words:
            return self._normalize_word_count(words, transcript.split())

        # Older whisper versions may lack word_timestamps. Use segment duration
        # as a last real-ASR fallback, then distribute transcript words inside each segment.
        transcript_words = transcript.split()
        if not transcript_words:
            return []
        duration = self._probe_audio_duration(audio_path)
        return self._evenly_distribute(transcript_words, duration)

    def _probe_audio_duration(self, audio_path: str) -> float:
        ffprobe = getattr(settings, "ffprobe_binary", "ffprobe") or "ffprobe"
        if not shutil.which(ffprobe):
            raise ASRAlignmentError(f"ffprobe not found: {ffprobe}")
        proc = subprocess.run(
            [ffprobe, "-v", "error", "-show_entries", "format=duration", "-of", "default=nokey=1:noprint_wrappers=1", audio_path],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
            timeout=20,
        )
        if proc.returncode != 0:
            raise ASRAlignmentError(proc.stderr.strip() or f"ffprobe failed for {audio_path}")
        return float(proc.stdout.strip())

    @staticmethod
    def _evenly_distribute(words: list[str], duration_sec: float) -> list[dict]:
        per_word = duration_sec / max(1, len(words))
        return [
            {"word": word, "start_sec": round(idx * per_word, 3), "end_sec": round((idx + 1) * per_word, 3)}
            for idx, word in enumerate(words)
        ]

    def _normalize_word_count(self, marks: list[dict], transcript_words: list[str]) -> list[dict]:
        if not marks:
            return []
        # Preserve ASR timing but replace rendered text with canonical transcript words
        # when counts match. This prevents punctuation/casing drift from breaking karaoke.
        if len(marks) == len(transcript_words):
            return [{**mark, "word": transcript_words[idx]} for idx, mark in enumerate(marks)]
        return marks
